			allowed++
		}
	}
	if allowed != 2 {
		t.Fatalf("after one window, expected 2 allowed (Rate), got %d", allowed)
	}
}

func TestBurstDefaultEqualsRate(t *testing.T) {
	clock := NewTestClock(epoch)
	lim := NewLimiter(Config{Rate: 4, Window: time.Second, Burst: 0}, clock)

